class Solution:
    def findAllPeople(self, n: int, meetings: List[List[int]], firstPerson: int) -> List[int]:
        graph = [[] for _ in range(n)]
        for x, y, _ in meetings:
            graph[x].append(y)
            graph[y].append(x)
        uf = list(range(n))
        def find(x):
            if uf[x] != x:
                uf[x] = find(uf[x])
            return uf[x]
        def union(x, y):
            uf[find(x)] = find(y)
        union(0, firstPerson)
        for x, y, time in sorted(meetings, key=lambda x: x[2]):
            if find(x) == find(0):
                union(x, y)
            if find(y) == find(0):
                union(y, x)
        return [i for i in range(n) if find(i) == find(0)]
